  "questionProse": [
    "מה הפלט של הקוד הבא?"
  ],
  "hintsProse": [
    "בדוק את הסמנטיקה המדויקת של האופרטור ב-JavaScript. התשובה המפתה היא לעתים קרובות מה שתחביר ישן יותר היה עושה, לא מה שהתכונה הזו עושה."
  ],
  "explanationProse": [
    "אופרטור השרשור האופציונלי (`?.`) מפסיק את ההערכה אם הצד השמאלי הוא `null` או `undefined`. מכיוון ש-`obj.foo` הוא `null`, `obj.foo?.bar` מוערך ל-`undefined`."
  ]
}
